def get_instance(self, instance, zone, project_id=None):
    """
    Retrieve a Compute Engine instance by name in a given zone.
    If project_id is not provided, uses self.project_id.
    """
    if project_id is None:
        project_id = self.project_id
    if not project_id:
        raise ValueError("project_id must be provided either as an argument or set on self.project_id")

    return self.get_conn().instances().get(
        project=project_id,
        zone=zone,
        instance=instance
    ).execute(num_retries=self.num_retries)
